import{_ as e,a,b as d,c as o}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as r,o as l,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"S3 互換チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/s3.md","filePath":"ja-JP/upload/s3.md","lastUpdated":1781962217000}'),c={name:"ja-JP/upload/s3.md"};function n(p,t,h,u,b,m){return l(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="s3-互換チャンネルの追加" tabindex="-1">S3 互換チャンネルの追加 <a class="header-anchor" href="#s3-互換チャンネルの追加" aria-label="Permalink to &quot;S3 互換チャンネルの追加&quot;">​</a></h1><p>S3 チャンネルは、S3 API に対応したオブジェクトストレージを ImgBed の保存先として利用します。</p><p>Cloudflare R2、Backblaze B2、MinIO、AWS S3、自前の S3 互換サービスなどに対応できます。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>オブジェクトストレージの API URL</td></tr><tr><td>Bucket 名</td><td>ファイルを保存するバケット</td></tr><tr><td>Region</td><td>ストレージのリージョン。Cloudflare R2 は通常 <code>auto</code></td></tr><tr><td>Access Key ID</td><td>S3 アクセスキー</td></tr><tr><td>Secret Access Key</td><td>S3 シークレットキー</td></tr><tr><td>CDN ドメイン</td><td>任意。独自の配信ドメインを使う場合</td></tr></tbody></table><p>Cloudflare R2 の S3 API 例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://あなたのAccountID.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: R2バケット名</span></span>
<span class="line"><span>Region: auto</span></span></code></pre></div><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><ol><li>システム設定を開きます。</li><li>アップロード設定を開きます。</li><li>「チャンネル追加」をクリックします。</li><li><code>S3</code> を選択します。</li></ol><h2 id="入力項目" tabindex="-1">入力項目 <a class="header-anchor" href="#入力項目" aria-label="Permalink to &quot;入力項目&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>R2-S3</code>、<code>MinIO</code></td></tr><tr><td>Endpoint</td><td><code>https://</code> を含む S3 API URL</td></tr><tr><td>カスタム CDN ドメイン</td><td>任意。設定時はリンク生成に優先利用します</td></tr><tr><td>Bucket 名</td><td>保存先バケット</td></tr><tr><td>Region</td><td>R2 は <code>auto</code>、他はサービス仕様に合わせます</td></tr><tr><td>Access Key ID</td><td>S3 アクセスキー</td></tr><tr><td>Secret Access Key</td><td>S3 シークレットキー</td></tr><tr><td>Path-style access</td><td>MinIO や一部互換サービスで必要な場合だけオン</td></tr><tr><td>容量制限</td><td>必要に応じてオン</td></tr></tbody></table><h2 id="r2-で-s3-キーを作る" tabindex="-1">R2 で S3 キーを作る <a class="header-anchor" href="#r2-で-s3-キーを作る" aria-label="Permalink to &quot;R2 で S3 キーを作る&quot;">​</a></h2><p>Cloudflare Dashboard で <code>R2 Object Storage</code> を開き、API Token 管理へ進みます。</p><p>![R2 API Token 入口](../../image/upload/s3/r2 api token入口.png)</p><p>対象バケットへアクセスできる R2 API Token を作成します。</p><p><img src="`+e+'" alt="API Token 作成" loading="lazy"></p><p>生成された <code>Access Key ID</code> と <code>Secret Access Key</code> をコピーします。</p><p><img src="'+a+'" alt="Token 値コピー" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><ol><li><code>Endpoint</code>、<code>Bucket</code>、<code>Region</code> を入力します。</li><li>Access Key ID と Secret Access Key を入力します。</li><li>CDN を使う場合だけカスタム CDN ドメインを入力します。</li><li>Path-style access は必要な場合のみオンにします。</li><li>保存します。</li></ol><p><img src="'+d+'" alt="S3 設定" loading="lazy"></p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>確認項目</th><th>正常な状態</th></tr></thead><tbody><tr><td>チャンネルカード</td><td>保存後に表示される</td></tr><tr><td>テストアップロード</td><td>対象 Bucket にオブジェクトが作成される</td></tr><tr><td>リンク</td><td>ImgBed が返した URL を開ける</td></tr><tr><td>容量表示</td><td>容量制限を使う場合、使用量が表示される</td></tr></tbody></table><p><img src="'+o+'" alt="容量表示" loading="lazy"></p><p>S3 の容量統計は、保存先 API を毎回リアルタイムに走査するのではなく、ImgBed の D1 ファイル記録から再計算されます。</p><h2 id="よくある原因" tabindex="-1">よくある原因 <a class="header-anchor" href="#よくある原因" aria-label="Permalink to &quot;よくある原因&quot;">​</a></h2><ul><li>Endpoint に <code>https://</code> がない。</li><li>Bucket 名または Region が違う。</li><li>Access Key に書き込み権限がない。</li><li>サービス側が Path-style access を必要としている。</li><li>CDN ドメインが Bucket と正しく接続されていない。</li></ul>',27)])])}const k=r(c,[["render",n]]);export{_ as __pageData,k as default};
